import{_ as i,C as t,o as l,c,ag as o,E as a,w as r,a as n}from"./chunks/framework.BZohXCq9.js";const P=JSON.parse('{"title":"Configuración","description":"Medios de pago, moneda, PIN de acceso e información de tu plan","frontmatter":{"title":"Configuración","description":"Medios de pago, moneda, PIN de acceso e información de tu plan"},"headers":[],"relativePath":"studio/seccion-config.md","filePath":"studio/seccion-config.md"}'),u={name:"studio/seccion-config.md"};function p(g,e,h,m,b,q){const d=t("Warning"),s=t("Note");return l(),c("div",null,[e[2]||(e[2]=o('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p><strong>Configuración</strong> es el último tab de tu panel. Desde aquí controlas los aspectos técnicos de tu negocio: qué métodos de pago aceptas, cómo se muestran los precios, tu PIN de acceso y la información de tu plan actual.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Configuración</strong> (último ícono en el menú lateral, ⚙️)</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="barra-superior-tasas-bcv" tabindex="-1">Barra superior: Tasas BCV <a class="header-anchor" href="#barra-superior-tasas-bcv" aria-label="Permalink to &quot;Barra superior: Tasas BCV&quot;">​</a></h3><p>En la parte superior verás:</p><ul><li><strong>Tasa USD:</strong> El precio del dólar en bolívares según el BCV</li><li><strong>Tasa EUR:</strong> El precio del euro en bolívares según el BCV</li><li><strong>Botón &quot;Actualizar&quot;</strong> — Refresca las tasas manualmente</li></ul><p>La tasa BCV se actualiza automáticamente todos los días. Si necesitas el dato al momento, dale clic a &quot;Actualizar&quot;.</p><h3 id="seccion-metodos-de-pago-izquierda" tabindex="-1">Sección: Métodos de Pago (izquierda) <a class="header-anchor" href="#seccion-metodos-de-pago-izquierda" aria-label="Permalink to &quot;Sección: Métodos de Pago (izquierda)&quot;">​</a></h3><p>Aquí seleccionas qué métodos de pago acepta tu negocio. Se muestran como checkboxes organizados en dos grupos:</p><p><strong>Nacionales (11 métodos):</strong> Pago Móvil, Efectivo, Punto de Venta, Biopago, Cashea, Krece, Wepa, Lysto, Chollo, Wally, Kontigo</p><p><strong>Internacionales (7 métodos):</strong> Zelle, PayPal, Zinli, AirTM, Reserve (RSV), Binance Pay, USDT</p><p><strong>Monedas aceptadas (2):</strong> USD, EUR</p><p>Cada checkbox se colorea al activarse (fondo azul claro). Un área de <strong>preview</strong> muestra cómo se verán los chips en la landing.</p><p>Botón: <strong>&quot;Guardar Métodos de Pago&quot;</strong></p>',16)),a(d,null,{default:r(()=>[...e[0]||(e[0]=[n(' En el plan **Oportunidad**, esta sección está bloqueada. Solo se muestran Pago Móvil y Efectivo fijos, con un mensaje: *"Más métodos disponibles desde Plan CRECIMIENTO"*. ',-1)])]),_:1}),e[3]||(e[3]=o('<p>En el plan <strong>Visión</strong> aparece una sección adicional colapsable: <strong>&quot;Métodos por Sucursal&quot;</strong> — permite configurar métodos de pago diferentes para cada sucursal.</p><p>→ Para más detalles, chequea <a href="/studio/medios-de-pago.html">Medios de pago</a></p><h3 id="seccion-moneda-derecha" tabindex="-1">Sección: Moneda (derecha) <a class="header-anchor" href="#seccion-moneda-derecha" aria-label="Permalink to &quot;Sección: Moneda (derecha)&quot;">​</a></h3><p>Configura cómo se muestran los precios en tu landing:</p><table tabindex="0"><thead><tr><th>Modo</th><th>Símbolo</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Solo referencia</strong> (<code>reference_only</code>)</td><td>REF o $</td><td>Muestra solo el precio en dólares</td></tr><tr><td><strong>Solo bolívares</strong> (<code>bolivares_only</code>)</td><td>Bs.</td><td>Muestra solo el precio en bolívares</td></tr><tr><td><strong>Ambos con toggle</strong> (<code>both_toggle</code>)</td><td>REF/Bs.</td><td><strong>Por defecto.</strong> Tu cliente puede cambiar entre REF y Bs.</td></tr><tr><td><strong>Euro con toggle</strong> (<code>euro_toggle</code>)</td><td>€/Bs.</td><td>Muestra euros y bolívares con toggle</td></tr><tr><td><strong>Ocultar</strong> (<code>hidden</code>)</td><td>—</td><td>Oculta los precios. Muestra &quot;Más Info&quot; en su lugar</td></tr></tbody></table><p>También puedes elegir el <strong>símbolo de referencia</strong>: REF o $.</p><p>Botón: <strong>&quot;Guardar Moneda&quot;</strong></p><h3 id="seccion-pin-de-acceso-izquierda-inferior" tabindex="-1">Sección: PIN de Acceso (izquierda inferior) <a class="header-anchor" href="#seccion-pin-de-acceso-izquierda-inferior" aria-label="Permalink to &quot;Sección: PIN de Acceso (izquierda inferior)&quot;">​</a></h3><p>Tu PIN de 4 dígitos es lo que protege el acceso a tu panel. Desde aquí puedes cambiarlo:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>PIN actual</strong></td><td>Tu PIN de 4 dígitos actual</td></tr><tr><td><strong>Nuevo PIN</strong></td><td>El nuevo PIN que quieres usar</td></tr><tr><td><strong>Confirmar PIN</strong></td><td>Repite el nuevo PIN</td></tr></tbody></table><p>Botón: <strong>&quot;Guardar PIN&quot;</strong></p>',11)),a(s,null,{default:r(()=>[...e[1]||(e[1]=[n(" El PIN debe ser exactamente 4 dígitos numéricos (0-9). No uses PINs obvios como 0000 o 1234. ",-1)])]),_:1}),e[4]||(e[4]=o('<h3 id="seccion-tu-plan-derecha-inferior" tabindex="-1">Sección: Tu Plan (derecha inferior) <a class="header-anchor" href="#seccion-tu-plan-derecha-inferior" aria-label="Permalink to &quot;Sección: Tu Plan (derecha inferior)&quot;">​</a></h3><p>Muestra información de tu plan actual:</p><table tabindex="0"><thead><tr><th>Dato</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Badge de plan</strong></td><td>Color según plan: 🟡 Oportunidad, 🟢 Crecimiento, 🔵 Visión</td></tr><tr><td><strong>Nombre del plan</strong></td><td>Tu plan actual</td></tr><tr><td><strong>Productos</strong></td><td>X de Y usados (ej: &quot;8 de 20&quot;)</td></tr><tr><td><strong>Servicios</strong></td><td>X de Y usados (ej: &quot;2 de 3&quot;)</td></tr><tr><td><strong>Miembro desde</strong></td><td>Fecha de registro</td></tr><tr><td><strong>Renovación</strong></td><td>Fecha de próxima renovación</td></tr></tbody></table><p>Botón: <strong>&quot;Ver planes disponibles&quot;</strong> — abre la página de planes</p><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No permite cambiar de plan directamente desde el panel</li><li>No procesa pagos de renovación</li><li>No tiene historial de cambios de configuración</li><li>No permite agregar métodos de pago personalizados (solo los 18 predefinidos)</li><li>No tiene modo de prueba/sandbox</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Oportunidad</th><th>Crecimiento</th><th>Visión</th></tr></thead><tbody><tr><td>Tasas BCV</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Métodos de pago configurables</td><td>❌ (fijo: Pago Móvil + Efectivo)</td><td>✅ (18 métodos)</td><td>✅ (18 métodos + por sucursal)</td></tr><tr><td>Monedas (USD/EUR)</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Modo de moneda</td><td>✅</td><td>✅</td><td>✅ (+ euro_toggle)</td></tr><tr><td>Cambiar PIN</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Info del plan</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-ferreteria-el-tornillo-en-puerto-ordaz" tabindex="-1">Caso: Ferretería &quot;El Tornillo&quot; en Puerto Ordaz <a class="header-anchor" href="#caso-ferreteria-el-tornillo-en-puerto-ordaz" aria-label="Permalink to &quot;Caso: Ferretería &quot;El Tornillo&quot; en Puerto Ordaz&quot;">​</a></h3><p>José tiene una ferretería con plan Crecimiento. Va a <strong>Configuración</strong>:</p><ol><li><strong>Métodos de Pago:</strong> Activa Pago Móvil, Efectivo, Punto de Venta y Zelle</li><li><strong>Moneda:</strong> Selecciona &quot;Ambos con toggle&quot; para que sus clientes vean precios en REF y en Bs.</li><li><strong>PIN:</strong> Cambia su PIN de 1234 a 5678</li><li><strong>Tu Plan:</strong> Chequea que tiene 12 de 50 productos usados</li></ol><p>Sus clientes ahora ven en la landing los 4 métodos de pago como chips, y pueden alternar entre REF y bolívares para ver los precios.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/medios-de-pago.html">Medios de pago</a> — Detalle de los 18 métodos disponibles</li><li><a href="/shared/moneda-y-precios.html">Moneda y precios</a> — Cómo funciona la tasa BCV y los modos de moneda</li><li><a href="/studio/panel-flotante.html">Panel flotante</a> — Cómo acceder al panel</li></ul>',15))])}const _=i(u,[["render",p]]);export{P as __pageData,_ as default};
